状态计算 <pre><code>#include&lt;bits/stdc++.h&gt;
using namespace std;
const int N=55,mod=1000000007;
int n,m,k;
int w[N][N];
int f[N][N][13][14];

int main()
{
    cin&gt;&gt;n&gt;&gt;m&gt;&gt;k;
    for(int i=1;i&lt;=n;i++)
    {
        for(int j=1;j&lt;=m;j++)
        {
            cin&gt;&gt;w[i][j];
            w[i][j]++;  //物品价值的取值范围是0~12 我们手动改成1~13 把0作为一个边界点
        }
    }    

    //第一个选或不选都算是一种方案
    f[1][1][1][w[1][1]]=1;
    f[1][1][0][0]=1;

    for(int i=1;i&lt;=n;i++)
    {
        for(int j=1;j&lt;=m;j++)
        {
            if(i==1 &amp;&amp; j==1) continue;
            for(int u=0;u&lt;=k;u++)
            {
                for(int v=0;v&lt;=13;v++)
                {

                    //不取
                    f[i][j][u][v]=(f[i][j][u][v]+f[i][j-1][u][v])%mod;
                    f[i][j][u][v]=(f[i][j][u][v]+f[i-1][j][u][v])%mod;
                    //取
                    if(u&gt;0 &amp;&amp; v==w[i][j])  //u为0的意思就是一个都不取  当满足c=w[i][j]的时候才能取 因为要取的数是当前最大的
                    {
                        for(int c=0;c&lt;v;c++)
                        {
                            f[i][j][u][v]=(f[i][j][u][v]+f[i-1][j][u-1][c])%mod;
                            f[i][j][u][v]=(f[i][j][u][v]+f[i][j-1][u-1][c])%mod;
                        }
                    }
                }
            }
        }
    }

    int res=0;
    for(int i=0;i&lt;=13;i++)  //把每种结果都累加一下
    {
        res=(res+f[n][m][k][i])%mod;
    }
    cout&lt;&lt;res;

    return 0;
}
</code></pre>

